class Solution:
    def colorTheArray(self, n, queries):
        arr = [0] * n
        answer = []
        for idx, color in queries:
            arr[idx] = color
            count = 0
            for j in range(n - 1):
                if arr[j] != 0 and arr[j] == arr[j + 1]:
                    count += 1
            answer.append(count)
        return answer

