var colorTheArray = function(n, queries) {
    const arr = new Array(n).fill(0);
    let total = 0;
    const answer = [];
    for (const [idx, color] of queries) {
        if (idx > 0 && arr[idx - 1] !== 0 && arr[idx - 1] === arr[idx]) total -= 1;
        if (idx < n - 1 && arr[idx + 1] !== 0 && arr[idx + 1] === arr[idx]) total -= 1;
        arr[idx] = color;
        if (idx > 0 && arr[idx - 1] !== 0 && arr[idx - 1] === arr[idx]) total += 1;
        if (idx < n - 1 && arr[idx + 1] !== 0 && arr[idx + 1] === arr[idx]) total += 1;
        answer.push(total);
    }
    return answer;
};
